const Dashboard: React.FC = () => {
    const { pageData, setDashboardData, isSeasonalModeActive } = usePageData();
    const { overview, error } = pageData.dashboard;
    const [isLoading, setIsLoading] = useState(!overview);
    const [cooldown, setCooldown] = useState(0);
    const navigate = useNavigate();

    const [biasIndex, setBiasIndex] = useState(0);

    const fetchDashboard = async (force = false) => {
        const now = Date.now();
        const lastUpdate = overview?.lastUpdated || 0;
        const timeSinceLastUpdate = now - lastUpdate;

        // Don't auto-refresh more than once every 5 minutes unless forced
        if (!force && overview && timeSinceLastUpdate < 300000) {
            return;
        }

        // Prevent rapid-fire manual syncing
        if (force && timeSinceLastUpdate < 60000) {
            const waitSeconds = Math.ceil((60000 - timeSinceLastUpdate) / 1000);
            setCooldown(waitSeconds);
            setTimeout(() => setCooldown(0), 2000);
            return;
        }

        setIsLoading(true);
        try {
            const data = await getDashboardOverview(isSeasonalModeActive);
            setDashboardData({ overview: data, error: null });
        } catch (err: any) {
            setDashboardData({ overview: overview, error: err.message || 'Neural Link Error' });
        } finally {
            setIsLoading(false);
