import React, { useEffect, useState, useMemo } from 'react';
import { getDashboardOverview } from '../services/dashboardService';
import { DashboardOverview, DailyBias } from '../types';
import Spinner from './Spinner';
import ErrorDisplay from './ErrorDisplay';
import { usePageData } from '../hooks/usePageData';
import { useNavigate } from 'react-router-dom';
import SeasonalModeToggle from './SeasonalModeToggle';

const safeText = (val: any): string => {
    if (val === null || val === undefined) return '';
    if (typeof val === 'string') return val;
    if (typeof val === 'number') return String(val);
    try {
        if (typeof val === 'object') {
            const keys = Object.keys(val);
            if (keys.length === 1) return String(val[keys[0]]);
            return JSON.stringify(val);
        }
        return String(val);
    } catch (e) {
        return 'Data Error';
    }
};

const safeArray = (val: any): any[] => {
    if (Array.isArray(val)) return val;
    if (val === null || val === undefined) return [];
    return [val];
};

const SectionHeader: React.FC<{ icon: string; title: string }> = ({ icon, title }) => (
    <div className="flex items-center gap-2 mb-4">
        <i className={`${icon} text-red-500`}></i>
        <h3 className="text-[10px] font-black text-white uppercase tracking-[0.2em]">{title}</h3>
    </div>
);

const VolatilityMeter: React.FC<{ level: string }> = ({ level }) => {
    const bars = level.toLowerCase() === 'high' ? 3 : level.toLowerCase() === 'medium' ? 2 : 1;
    return (
        <div className="flex gap-1 items-center">
            {[1, 2, 3].map(i => (
                <div key={i} className={`w-1.5 h-4 rounded-sm ${i <= bars ? 'bg-yellow-500 shadow-[0_0_8px_rgba(234,179,8,0.5)]' : 'bg-gray-700'}`}></div>
            ))}
            <span className="ml-2 text-xs font-bold text-white uppercase">{level}</span>
        </div>
    );
};

const Dashboard: React.FC = () => {
    const { pageData, setDashboardData, isSeasonalModeActive } = usePageData();
    const { overview, error } = pageData.dashboard;
    const [isLoading, setIsLoading] = useState(!overview);
    const [cooldown, setCooldown] = useState(0);
    const navigate = useNavigate();

    const [biasIndex, setBiasIndex] = useState(0);

    const fetchDashboard = async (force = false) => {
        const now = Date.now();
        const lastUpdate = overview?.lastUpdated || 0;
        const timeSinceLastUpdate = now - lastUpdate;

        if (!force && overview && timeSinceLastUpdate < 300000) return;

        if (force && timeSinceLastUpdate < 60000) {
            const waitSeconds = Math.ceil((60000 - timeSinceLastUpdate) / 1000);
            setCooldown(waitSeconds);
            setTimeout(() => setCooldown(0), 2000);
            return;
        }

        setIsLoading(true);
        try {
            const data = await getDashboardOverview(isSeasonalModeActive);
            setDashboardData({ overview: data, error: null });
        } catch (err: any) {
            setDashboardData({ overview: overview, error: err.message || 'Neural Link Error' });
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchDashboard();
    }, [isSeasonalModeActive]);

    useEffect(() => {
        const biases = safeArray(overview?.dailyBiases);
        if (biases.length === 0) return;
        const itv = setInterval(() => setBiasIndex(prev => (prev + 1) % biases.length), 10000);
        return () => clearInterval(itv);
    }, [overview]);

    if (isLoading && !overview) return <div className="py-24 flex justify-center"><Spinner /></div>;

    const safeBiases = safeArray(overview?.dailyBiases);
    const currentBias = safeBiases[biasIndex];

    return (
        <div className="space-y-6 pb-10 px-4 max-w-7xl mx-auto glass-fix">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
                <div>
                    <h1 className="text-4xl font-black text-gray-900 dark:text-cyan-400 uppercase tracking-tight">Global Market Pulse</h1>
                    <p className="text-[11px] text-gray-500 font-bold uppercase tracking-widest mt-1">AI-powered real-time market intelligence.</p>
                </div>
                {overview && (
                    <div className="text-[10px] font-black text-gray-500 uppercase tracking-widest bg-black/10 dark:bg-white/5 px-3 py-1 rounded-md">
                        Last Update: {new Date(overview.lastUpdated).toLocaleTimeString()}
                    </div>
                )}
            </div>

            {/* Seasonal Toggle Subheader */}
            <div className="bg-white/10 dark:bg-black/40 backdrop-blur-xl ring-1 ring-white/20 dark:ring-white/10 rounded-2xl p-4 flex flex-col md:flex-row justify-between items-center gap-4 glass-fix">
                <div className="flex items-center gap-3">
                    <i className="fas fa-snowflake text-blue-400 text-xl"></i>
                    <div>
                        <span className="block text-xs font-black text-white uppercase tracking-widest">Seasonal Mode</span>
                        <div className="flex items-center gap-2 text-[10px]">
                            <div className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,1)]"></div>
                            <span className="text-gray-400">Status: <span className="text-green-500 font-bold">Active</span> (Auto)</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                     <button 
                        onClick={() => fetchDashboard(true)} 
                        disabled={isLoading || cooldown > 0}
                        className={`p-2 rounded-lg transition-all ${isLoading ? 'opacity-50' : 'hover:bg-white/5'}`}
                    >
                        <i className={`fas fa-sync ${isLoading ? 'animate-spin' : ''} text-blue-400`}></i>
                    </button>
                    <div className="h-8 w-px bg-white/10"></div>
                    <SeasonalModeToggle />
                </div>
            </div>

            {error && <ErrorDisplay error={error} />}

            {overview && (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 glass-fix">

                    {/* LEFT COLUMN - Market Condition & Scanner */}
                    <div className="lg:col-span-8 space-y-6">

                        {/* Market Condition Header */}
                        <div className="bg-white/5 dark:bg-black/60 backdrop-blur-2xl ring-1 ring-white/10 rounded-2xl p-6 shadow-xl glass-fix">
                            <SectionHeader icon="fas fa-globe" title="Market Condition" />
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                                <div>
                                    <span className="block text-[9px] text-gray-500 uppercase font-black tracking-widest mb-2">Sentiment</span>
                                    <span className="bg-gray-500/20 text-white px-3 py-1.5 rounded-md text-[10px] font-black uppercase tracking-widest border border-white/5 block text-center">
                                        {overview.marketCondition?.sentiment || 'NEUTRAL'}
                                    </span>
                                </div>
                                <div>
                                    <span className="block text-[9px] text-gray-500 uppercase font-black tracking-widest mb-2">Volatility</span>
                                    <VolatilityMeter level={overview.marketCondition?.volatility || 'Medium'} />
                                </div>
                                <div>
                                    <span className="block text-[9px] text-gray-500 uppercase font-black tracking-widest mb-2">Active Session</span>
                                    <div className="bg-blue-900/20 border border-blue-500/30 text-blue-200 px-3 py-1.5 rounded-md text-[10px] font-black uppercase tracking-tight text-center">
                                        {overview.marketCondition?.dominantSession || 'London/NY Overlap'}
                                    </div>
