const OpportunityFinder: React.FC<{ assets: HeatmapAsset[] }> = ({ assets }) => {
    const [mode, setMode] = useState<HeatmapMode>('performance');

    const getBoxStyle = (asset: HeatmapAsset) => {
        let size = '100%';
        let bgColor = 'bg-gray-800';

        if (mode === 'volume') {
            const scale = Math.min(Math.max(asset.volumeRatio, 0.5), 2);
            size = `${scale * 100}%`;
        }

        // Color Logic
        if (mode === 'technical') {
            if (asset.rsi < 30) bgColor = 'bg-blue-600'; // Oversold
            else if (asset.rsi > 70) bgColor = 'bg-orange-600'; // Overbought
            else bgColor = 'bg-gray-700';
        } else if (mode === 'reversion') {
            if (asset.zScore > 2) bgColor = 'bg-red-900';
            else if (asset.zScore < -2) bgColor = 'bg-green-900';
            else bgColor = 'bg-gray-700';
        } else {
            bgColor = asset.change24h >= 0 ? 'bg-emerald-900/60' : 'bg-rose-900/60';
        }

        return { size, bgColor };
    };

    return (
        <div className="space-y-4">
            <div className="flex flex-wrap gap-2 mb-2 px-1">
                {(['performance', 'volume', 'technical', 'reversion'] as HeatmapMode[]).map(m => (
                    <button 
                        key={m}
                        onClick={() => setMode(m)}
                        className={`text-[8px] font-black uppercase tracking-widest px-2.5 py-1.5 rounded-lg border transition-all ${mode === m ? 'bg-red-600 border-red-500 text-white' : 'bg-white/5 border-white/10 text-gray-500 hover:text-white'}`}
                    >
                        {m === 'reversion' ? 'Z-Score' : m}
                    </button>
                ))}
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-3 h-[280px]">
                {safeArray(assets).slice(0, 12).map((asset, i) => {
                    const { size, bgColor } = getBoxStyle(asset);
                    return (
                        <div key={i} className="relative group overflow-hidden rounded-xl border border-white/5 flex items-center justify-center bg-black/40">
                            <div 
                                className={`absolute transition-all duration-700 rounded-lg ${bgColor}`}
                                style={{ width: size, height: size, opacity: 0.4 }}
                            ></div>
                            <div className="relative z-10 text-center p-2">
                                <span className="block text-xs font-black text-white mb-0.5">{asset.symbol}</span>
                                <span className={`text-[10px] font-bold ${asset.change24h >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                                    {asset.change24h >= 0 ? '+' : ''}{asset.change24h}%
                                </span>
                                <div className="hidden group-hover:block absolute top-full left-1/2 -translate-x-1/2 mt-2 w-32 bg-black/90 backdrop-blur-xl p-2 rounded-lg border border-white/20 text-[8px] font-bold space-y-1 shadow-2xl z-50">
                                    <div className="flex justify-between"><span>RSI:</span> <span className={asset.rsi > 70 ? 'text-orange-400' : asset.rsi < 30 ? 'text-blue-400' : 'text-white'}>{asset.rsi}</span></div>
                                    <div className="flex justify-between"><span>Volume:</span> <span>{asset.volumeRatio}x</span></div>
                                    <div className="flex justify-between"><span>Z-Score:</span> <span>{asset.zScore}</span></div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

