                        </div>
                    </div>

                    <div className="lg:col-span-4 bg-white/5 dark:bg-black/60 backdrop-blur-2xl ring-1 ring-white/10 rounded-[2rem] shadow-xl p-6 glass-fix flex flex-col h-[500px]">
