                                            <span className="block text-xs font-black text-white">{item.symbol}</span>
                                            <span className="text-[10px] font-bold text-gray-500 uppercase">{item.price || '---'}</span>
                                        </div>
                                        <div className="text-right">
                                            <span className={`text-[10px] font-black px-2 py-1 rounded-md ${changeVal.includes('-') ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}>
                                                {changeVal}
                                            </span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <div className="mt-4 pt-4 border-t border-white/5">
                             <div className="bg-blue-500/10 p-3 rounded-xl border border-blue-500/20">
                                <span className="block text-[8px] font-black text-blue-400 uppercase mb-1">Market Sentiment Index</span>
                                <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                                    <div className="h-full bg-blue-500" style={{ width: '68%' }}></div>
                                </div>
                                <div className="flex justify-between mt-1 text-[8px] font-black text-gray-500 uppercase">
                                    <span>Bearish</span>
                                    <span className="text-blue-400">68% Bullish</span>
                                </div>
                             </div>
                        </div>
                    </div>

                    {/* HEATMAPS ROW */}
