                                        </span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="lg:col-span-8 bg-white/5 dark:bg-black/60 backdrop-blur-2xl ring-1 ring-white/10 rounded-[2rem] shadow-xl p-6 glass-fix h-[420px]">
                        <SectionHeader icon="fas fa-project-diagram" title="The Opportunity Finder" subtitle="MULTI-DIMENSIONAL HEATMAP" />
                        <OpportunityFinder assets={overview.opportunityHeatmap} />
                    </div>

                </div>
            )}

            <style>{`.no-scrollbar::-webkit-scrollbar { display: none; }`}</style>
        </div>
    );
};

