                    <div className="lg:col-span-4 bg-white/5 dark:bg-black/60 backdrop-blur-2xl ring-1 ring-white/10 rounded-[2rem] shadow-xl p-6 glass-fix flex flex-col h-[500px]">
                        <SectionHeader icon="fas fa-list-ul" title="Dynamic Watchlist" />
                        <div className="flex-1 space-y-1 mt-2">
                            {safeArray(overview.watchlist).map((item, i) => {
                                const changeRaw = item.change24h;
                                let changeDisplay: string;
                                let isNegative: boolean;

                                if (typeof changeRaw === 'number') {
                                    changeDisplay = `${changeRaw > 0 ? '+' : ''}${changeRaw.toFixed(2)}%`;
                                    isNegative = changeRaw < 0;
                                } else {
                                    changeDisplay = String(changeRaw || '0.00%');
                                    isNegative = changeDisplay.includes('-');
                                }

                                return (
                                    <div key={i} className="flex justify-between items-center p-4 hover:bg-white/5 rounded-xl transition-all border-b border-white/5 last:border-0">
                                        <div>
                                            <span className="block text-xs font-black text-white">{item.symbol}</span>
                                            <span className="text-[10px] font-bold text-gray-500 uppercase">{item.price || '---'}</span>
                                        </div>
                                        <div className="text-right">
                                            <span className={`text-[10px] font-black px-2 py-1 rounded-md ${isNegative ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400'}`}>
                                                {changeDisplay}
                                            </span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <div className="mt-4 pt-4 border-t border-white/5">
                             <div className="bg-blue-500/10 p-3 rounded-xl border border-blue-500/20">
                                <span className="block text-[8px] font-black text-blue-400 uppercase mb-1">Market Sentiment Index</span>
                                <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                                    <div className="h-full bg-blue-500" style={{ width: '68%' }}></div>
                                </div>
                                <div className="flex justify-between mt-1 text-[8px] font-black text-gray-500 uppercase">
                                    <span>Bearish</span>
                                    <span className="text-blue-400">68% Bullish</span>
                                </div>
                             </div>
