import React, { createContext, useState, useContext, useEffect, ReactNode, useCallback } from 'react';
import { useEnvironment } from './useEnvironment';

// Define the context type
interface ApiKeyContextType {
  isKeyReady: boolean;
  promptForKey: () => Promise<void>;
  resetKeySelection: () => void;
}

// Create the context
const ApiKeyContext = createContext<ApiKeyContextType | undefined>(undefined);

// Extend the window interface for aistudio properties
declare global {
    interface Window {
        aistudio?: {
            hasSelectedApiKey: () => Promise<boolean>;
            openSelectKey: () => Promise<void>;
        }
        addEventListener(type: 'aistudio:apiKeySelected', listener: (this: Window, ev: Event) => any, options?: boolean | AddEventListenerOptions): void;
        addEventListener(type: 'resetApiKeySelection', listener: (this: Window, ev: Event) => any, options?: boolean | AddEventListenerOptions): void;
        removeEventListener(type: 'aistudio:apiKeySelected', listener: (this: Window, ev: Event) => any, options?: boolean | EventListenerOptions): void;
        removeEventListener(type: 'resetApiKeySelection', listener: (this: Window, ev: Event) => any, options?: boolean | EventListenerOptions): void;
    }
}

// The provider component
export const ApiKeyProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const environment = useEnvironment();
    const [isKeyReady, setIsKeyReady] = useState(false);
    const [isChecking, setIsChecking] = useState(true);

    const checkKey = useCallback(async () => {
        // Only run this logic in the AI Studio environment
        if (environment !== 'aistudio' || !window.aistudio) {
            setIsKeyReady(true);
            setIsChecking(false);
            return;
        }
        try {
            const hasKey = await window.aistudio.hasSelectedApiKey();
            setIsKeyReady(hasKey);
        } catch (e) {
            console.error("Error checking for API key:", e);
            setIsKeyReady(false);
        } finally {
            setIsChecking(false);
        }
    }, [environment]);

    const resetKeySelection = useCallback(() => {
        if (environment === 'aistudio') {
            setIsKeyReady(false);
        }
    }, [environment]);

    useEffect(() => {
        checkKey();
        // Add event listeners for key changes or reset requests
        window.addEventListener('aistudio:apiKeySelected', checkKey);
        window.addEventListener('resetApiKeySelection', resetKeySelection);
        return () => {
            window.removeEventListener('aistudio:apiKeySelected', checkKey);
            window.removeEventListener('resetApiKeySelection', resetKeySelection);
        };
    }, [checkKey, resetKeySelection]);

    const promptForKey = async () => {
        if (environment !== 'aistudio' || !window.aistudio) return;
        try {
            await window.aistudio.openSelectKey();
            // Per guidelines, assume success and proceed to avoid race conditions
            setIsKeyReady(true);
        } catch (e) {
            console.error("Error opening API key selection dialog:", e);
        }
    };

    const contextValue = { isKeyReady, promptForKey, resetKeySelection };

    // While checking, render nothing to avoid layout shifts
    if (isChecking) {
        return null;
    }

    // If key is ready, render the main app
    if (isKeyReady) {
        return <ApiKeyContext.Provider value={contextValue}>{children}</ApiKeyContext.Provider>;
    }

    // If key is not ready (and we are in AI Studio), render the selection prompt
    if (environment === 'aistudio') {
        return (
            <div className="flex flex-col items-center justify-center h-screen bg-gray-900 text-white p-4">
                <div className="text-center max-w-lg bg-black/30 backdrop-blur-md p-8 rounded-2xl border border-white/20">
                    <h1 className="text-2xl font-bold mb-4">API Key Required for Oracle Analyzer</h1>
                    <p className="mb-6 text-gray-300">
