    if (environment !== 'aistudio' || !ai) return "AI Studio only.";
    const response = await generateContentDirect({ model: 'gemini-3-flash-preview', contents: Prompts.getAutoFixPrompt(JSON.stringify(errors)) });
    return getValidatedTextFromResponse(response);
};

