    }

    try {
        const { action, payload } = req.body;

        if (!action) {
            if (req.body.command) {
                 const response = await ai.models.generateContent({
                    model: 'gemini-2.0-flash',
                    contents: req.body.command,
                    config: { tools: agentTools }
                });
