const ConfluenceScore: React.FC<{ score?: number }> = ({ score }) => {
    if (score === undefined || score < 0 || score > 10) return null;

    const percentage = score * 10;
    const circumference = 2 * Math.PI * 20; // radius 20
    const strokeDashoffset = circumference - (percentage / 100) * circumference;

    const getColor = () => {
        if (score >= 8) return { main: 'text-teal-500', stroke: '#14B8A6' };
        if (score >= 5) return { main: 'text-amber-500', stroke: '#F59E0B' };
        return { main: 'text-red-500', stroke: '#EF4444' };
    };
    const { main: color, stroke } = getColor();

    return (
        <div className={`p-3 rounded-lg border border-gray-500/20 bg-black/5 dark:bg-white/5`}>
            <div className="flex items-center justify-center space-x-3 text-center">
                 <div className="relative w-12 h-12">
                    <svg className="w-full h-full" viewBox="0 0 50 50">
                        <circle className="text-gray-200 dark:text-gray-700" strokeWidth="5" stroke="currentColor" fill="transparent" r="20" cx="25" cy="25"/>
                        <circle strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={strokeDashoffset} strokeLinecap="round" stroke={stroke} fill="transparent" r="20" cx="25" cy="25" transform="rotate(-90 25 25)" style={{ transition: 'stroke-dashoffset 0.8s ease-in-out' }}/>
                    </svg>
                    <span className={`absolute inset-0 flex items-center justify-center text-sm font-bold ${color}`}>{score.toFixed(1)}</span>
                </div>
                <div>
                    <p className="text-sm font-medium text-gray-600 dark:text-gray-400">Confluence</p>
                    <p className={`text-xl font-bold ${color}`}>{score}/10</p>
                </div>
            </div>
        </div>
    );
};


const Analysis: React.FC = () => {
    const location = useLocation();
    const navigate = useNavigate();
    const { result, error } = (location.state as AnalysisLocationState) || {};
    const { setEdgeLight } = useEdgeLighting();

    const onBack = () => navigate('/dashboard');

    const handleSelectKey = async () => {
        if ((window as any).aistudio) {
            try {
                await (window as any).aistudio.openSelectKey();
            } catch (e) {
                console.error(e);
            }
        }
    };

    useEffect(() => {
        if (result) {
            if (result.signal === 'BUY') setEdgeLight('green');
            else if (result.signal === 'SELL') setEdgeLight('red');
            else setEdgeLight('default'); // Falls back to blue/default
        } else {
            setEdgeLight('default');
        }
        // Cleanup to default when leaving
        return () => setEdgeLight('default');
    }, [result, setEdgeLight]);

    if (error) {
        const isPermissionError = error.toLowerCase().includes('permission denied') || error.toLowerCase().includes('api key');
        const isAIStudio = typeof window !== 'undefined' && (window as any).aistudio;

        return (
            <div className="text-center py-10">
                <h1 className="text-3xl font-bold text-red-600 dark:text-red-500 mb-4">Analysis Failed</h1>
                <ErrorDisplay error={error} />

                {isPermissionError && isAIStudio && (
                    <div className="mb-6">
                        <p className="text-gray-400 mb-4 text-sm max-w-md mx-auto">
                            The Oracle Analyzer uses advanced models that require a paid API key in AI Studio.
                        </p>
                        <button 
                            onClick={handleSelectKey}
                            className="bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 px-6 rounded-lg transition-colors shadow-lg"
                        >
                            Select Paid API Key
                        </button>
                    </div>
                )}

                <button onClick={onBack} className="inline-block bg-red-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-red-700 transition-colors">
                    {isPermissionError ? 'Return to Dashboard' : 'Try Again'}
                </button>
            </div>
        );
    }

    if (!result) {
        return (
          <div className="text-center py-10">
            <h1 className="text-3xl font-bold text-gray-800 dark:text-white mb-4">No Analysis Data</h1>
            <p className="text-gray-600 dark:text-gray-400 mb-8">
                Please go back to the dashboard and analyze a chart.
            </p>
            <button onClick={onBack} className="inline-block bg-red-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-red-700 transition-colors">
                Go to Dashboard
            </button>
          </div>
        );
    }

    // --- Data Validation and Sanitization ---
    const validatedSignal = ['BUY', 'SELL', 'NEUTRAL'].includes(result.signal) ? result.signal : 'NEUTRAL';
    const takeProfits = Array.isArray(result.takeProfits) 
        ? result.takeProfits 
        : (result.takeProfits ? [String(result.takeProfits)] : []);
